  /**
   * In event the convertible can convert due to trigger events (e.g. Maturity, Next Qualified Financing, Change of Control, at Election of Holder), what are the terms?
   * @minItems 1
   */
  conversion_triggers: (OCFAutomaticConversionOnConditionTrigger | OCFAutomaticConversionOnDateTrigger | OCFElectiveConversionAtWillTrigger | OCFElectiveConversionInDateRangeTrigger | OCFElectiveConversionOnConditionTrigger | OCFUnspecifiedConversionTrigger)[];
  /**
   * What pro-rata (if any) is the holder entitled to buy at the next round?
   */
